VALUES
  ('judicial-57f41407-moex-00493', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於實體法與程序法之關係，下列敘述何者錯誤？', '["實體法規範權利主體之權利義務；程序法是實現權利義務之手段與方法之法律", "民法為實體法，民事訴訟法為程序法", "實體法與程序法密不可分，兩者間相輔相成，以促進人民權利之實現", "法院審理時，必須依照「先實體後程序」之原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00494', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '有關法律適用之「三段論法」，下列敘述何者錯誤？', '["三段論法之大前提，即為法律規定之構成要件", "三段論法之小前提，即為具體個案之事實", "將具體個案事實置於法律規定之構成要件中，以得到結論，此過程稱為準用", "刑法第309條規定：「公然侮辱人者，處拘役或九千元以下罰金」，其中「公然侮辱人者」為構成要件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00495', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於法律解釋，下列敘述何者錯誤？', '["法律解釋的作用之一，在於其可因應時空背景改變所造成的法律適用落差", "在法律適用的步驟上，法律解釋應先於法律補充", "立法機關、司法機關及行政機關所作出的法律解釋由於會產生拘束力，故又稱為有權解釋", "若論理解釋與文義解釋所作出之結果互相衝突時，法官必須採用論理解釋之結果，以維持法律體系之一 致性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
